sql:
SELECT s.stock_name, s.market_cap, a.alert_type, a.threshold, a.message
FROM stocks s
INNER JOIN alerts a ON s.ticker = a.ticker;

SELECT *
FROM market_data
WHERE ticker = 'your_specific_ticker';

external_knowledge:
- "swim in the ocean of higher liquidity" metaphorically refers to stocks with higher trading volumes;
- "depth of trade waters" is a metaphor for the volume of trading;
- "average depth of trade waters across all stocks" indicates the average trading volume of all stocks.

sql:
SELECT ticker
FROM market_data
GROUP BY ticker
HAVING AVG(volume) > (
    SELECT AVG(volume) FROM market_data
);

SELECT portfolio_name 
FROM user_portfolios 
WHERE total_value = (
    SELECT MAX(total_value) 
    FROM user_portfolios
);

SELECT s.stock_name, ps.total_value 
FROM stocks s
INNER JOIN portfolio_stocks ps ON s.ticker = ps.ticker;
